function insertTextWithCursorOffset(editor, insertText, offset) {
  const cursorPos = editor.getCursor();
  editor.replaceRange(insertText, cursorPos);
  const newCursorPos = {
    line: cursorPos.line,
    ch: cursorPos.ch + offset
  };
  editor.setCursor(newCursorPos);
}

