async function mathCitationPostProcessor(plugin, el, ctx, citationCache) {
  const { citationPrefix } = plugin.settings;
  const sectionInfo = ctx.getSectionInfo(el);
  if (!sectionInfo) return;
  const citeSpans = getCitationSpan(el);
  if (!citeSpans) return;
  const allCitations = await citationCache.getCitationsForFile(ctx.sourcePath);
  if (!allCitations) return;
  const equations = allCitations.filter((eq) => eq.line >= sectionInfo.lineStart && eq.line <= sectionInfo.lineEnd);
  if (citeSpans.length === equations.length) {
    citeSpans.forEach((span, index) => {
      const eq = equations[index];
      const eqLabel = eq.label.substring(citationPrefix.length);
      const eqNumbers = eqLabel.split(plugin.settings.multiCitationDelimiter || ",").map((t) => t.trim());
      const eqNumbersAll = plugin.settings.enableContinuousCitation ? splitContinuousCitationTags(
        eqNumbers,
        plugin.settings.continuousRangeSymbol || "~",
        plugin.settings.continuousDelimiters.split(" ").filter((d) => d.trim()),
        plugin.settings.fileCiteDelimiter
      ) : eqNumbers;
      const citationWidget = renderEquationCitation(eqNumbersAll, plugin.settings);
      addReadingModePreviewListener(plugin, citationWidget, eqNumbersAll, ctx.sourcePath);
      span.replaceWith(citationWidget);
    });
  } else {
    new import_obsidian9.Notice("Equation Citator: Block render error, trun on debug mode and reopen file for details.");
    Debugger.warning(`Citation span number is: ${citeSpans.length},
But recognized citation count is : ${equations.length}, between line ${sectionInfo.lineStart} and ${sectionInfo.lineEnd}
Which is not match. this can cause rendering issue. skip rendering`);
  }
}
