// src/func/exportMarkdown.tsx
async function exportCurrentMarkdown(plugin) {
  const view = plugin.app.workspace.getActiveViewOfType(import_obsidian12.MarkdownView);
  if (!view)
    return;
  const file = view.file;
  if (!file)
    return;
  const md = await plugin.app.vault.read(file);
  const md_processed = makePrintMarkdown(md, plugin.settings);
  if (!md_processed) {
    new import_obsidian12.Notice("Nothing to export");
    return;
  }
  const originalName = file.name.replace(/\.md$/, "");
  const newName = originalName + "-exported.md";
  const folderPath = file.path.substring(0, file.path.lastIndexOf("/"));
  const newFilePath = folderPath + "/" + newName;
  const existingFile = plugin.app.vault.getAbstractFileByPath(newFilePath);
  if (existingFile instanceof import_obsidian12.TFile) {
    const confirmOption = {
      label: "Confirm",
      cta: true,
      action: async () => {
        try {
          await plugin.app.fileManager.trashFile(existingFile);
          await plugin.app.vault.create(newFilePath, md_processed);
          new import_obsidian12.Notice(`Exported to ${newFilePath}`);
        } catch (error) {
          new import_obsidian12.Notice(`Error: ${error.message}`);
        }
      }
    };
    const cancelOption = {
      label: "Cancel",
      cta: false,
      action: () => {
      }
    };
    new OptionsModal(
      plugin.app,
      "File already exists",
      `${newFilePath} already exists. Do you want to overwrite it?`,
      [confirmOption, cancelOption]
    ).open();
  } else {
    await plugin.app.vault.create(newFilePath, md_processed);
    new import_obsidian12.Notice(`Exported to ${newFilePath}`);
  }
}

