function parseFootnoteInMarkdown(markdown) {
  const lines = markdown.split("\n");
  const result = [];
  let inCodeBlock = false;
  for (const line of lines) {
    if (!line.startsWith("[^")) {
      if (isCodeBlockToggle(line)) {
        inCodeBlock = !inCodeBlock;
        continue;
      }
      continue;
    }
    if (inCodeBlock) {
      continue;
    }
    const match = line.match(footnoteRegex);
    if (match) {
      const num = match[1].substring(1);
      const path = match[2];
      const fileName = path.split("/").pop() || null;
      const label = match[3] && match[3].trim() !== "" ? match[3] : fileName;
      result.push({ num, path, label });
    }
  }
  return result;
}

