var import_obsidian18 = require("obsidian");
var TagRenameModal = class extends import_obsidian18.Modal {
  constructor(plugin, oldTag, sourceFile, heading = "Rename This Tag to :") {
    super(plugin.app);
    this.plugin = plugin;
    this.oldTag = oldTag;
    this.heading = heading;
  }
  setEditor(editor) {
    this.editor = editor;
  }
  onOpen() {
    this.titleEl.setText("Rename Tag");
    this.contentEl.addClass("ec-tag-rename-modal");
    this.newTag = this.oldTag;
    new import_obsidian18.Setting(this.contentEl).setName(this.heading).addText((text) => {
      text.setPlaceholder("New Tag Name");
      text.setValue(this.oldTag);
      text.inputEl.focus();
      text.inputEl.select();
      text.onChange((value) => {
        this.newTag = value;
      });
    });
    new import_obsidian18.Setting(this.contentEl).addButton((button) => {
      button.setButtonText("Rename Tag");
      button.setCta();
      button.onClick(async () => {
        const pair = {
          oldTag: this.oldTag,
          newTag: this.newTag
        };
        const filePath = this.app.workspace.getActiveFile()?.path;
        if (!filePath) {
          return;
        }
        await this.renameTag(filePath, pair);
        this.close();
      });
    }).addButton((button) => {
      button.setButtonText("Cancel");
      button.onClick(() => this.close());
    });
  }
  onClose() {
    this.contentEl.empty();
  }
  // override this method to handle submit event  
  onSubmit(newName) {
  }
  // rename tag by modal 
  async renameTag(filePath, pair) {
    const haveRepetedTags = await this.plugin.tagService.checkRepeatedTags(filePath, [pair]);
    const callRenameTagService = async (deleteRepeat, deleteUnused) => {
      const result = await this.plugin.tagService.renameTags(filePath, [pair], deleteRepeat, deleteUnused, this.editor);
      if (result) {
        const msg = assemblyCitationUpdateMessage(result);
        new import_obsidian18.Notice(msg);
      }
      this.onSubmit(this.newTag);
    };
    if (haveRepetedTags) {
      const deleteOption = {
        label: "Delete",
        cta: true,
        action: callRenameTagService.bind(this, true, false)
      };
      const keepOption = {
        label: "Keep",
        cta: false,
        action: callRenameTagService.bind(this, false, false)
      };
      const cancelOption = {
        label: "Cancel",
        cta: false,
        action: () => {
        }
        // do nothing when cancel button is clicked
      };
      const modal = new PromiseOptionsModal(
        this.app,
        "Citation Conflict",
        "There are citations with this name already, delete them or keep them?",
        [deleteOption, keepOption, cancelOption]
      );
      await modal.openWithPromise();
    } else {
      await callRenameTagService(false, false);
    }
  }
};

// src/ui/rightButtonMenu.tsx
function registerRightClickMenu(plugin) {
  const app = plugin.app;
  plugin.registerEvent(
    //  right click menu for tag rename 
    app.workspace.on("editor-menu", (menu, editor, view) => {
      let tagInfo;
      try {
        const state = editor.cm?.state;
        tagInfo = state.field(tagSelectedField);
      } catch (e) {
        Debugger.error("Can't get selected tag: ", e);
        return;
      }
      if (tagInfo.range && tagInfo?.tagSelected) {
        menu.addItem((item) => {
          item.setTitle("Rename equation tag");
          item.setIcon("pencil");
          item.onClick(() => {
            if (!tagInfo.tagContent) {
              Debugger.log("No tag content to rename");
              return;
            }
            const filePath = plugin.app.workspace.getActiveFile()?.path;
            if (!filePath) {
              Debugger.log("No active file to rename tag");
              return;
            }
            const modal = new TagRenameModal(plugin, tagInfo.tagContent, filePath);
            modal.setEditor(editor);
            modal.onSubmit = (newName) => {
              const newTag = `\\tag{${newName}}`;
              const fromPos = editor.getCursor("from");
              const toPos = editor.getCursor("to");
              editor.replaceRange(
                newTag,
                fromPos,
                toPos
              );
            };
            modal.open();
          });
        });
      }
    })
  );
}

